form:Form.form:Scripts:
function validarEmpresa()
		{ 

			if (g_CTRLs['oi_empresa'].GetCValue() == "")
				{	

					g_CTRLs['oi_liquidacion'].SetEnabled(false);
					g_CTRLs['oi_liquidacion'].SetCValue("");							
				} else
					{	

						g_CTRLs['oi_liquidacion'].SetCValue("");
						g_CTRLs['oi_liquidacion'].SetEnabled(true);

					}
		}
